// Noto Sans Hebrew (subset: Hebrew + Latin + punctuation), base64-encoded
// for embedding in jsPDF, since jsPDF's built-in fonts don't support Hebrew.
// Subsetted from Google Fonts' Noto Sans Hebrew (OFL licensed).
// The glyph mapped to U+200E (LRM) has been cleared to an empty outline --
// the original font draws a visible mark for this formatting character,
// which would otherwise show as a stray symbol before Hebrew text (LRM is
// used internally to work around a separate jsPDF digit-reversal bug; see
// pdfInvoiceHebrew.js for details).

export const NOTO_SANS_HEBREW_REGULAR = ''

export const NOTO_SANS_HEBREW_BOLD = ''
